package com.chrisb97.warehouse.validation;
import com.chrisb97.warehouse.exception.ValidationException;import com.chrisb97.warehouse.model.Product;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;
class ProductValidatorTest{private Product valid(){Product p=new Product();p.setSku("SKU-1");p.setName("Product");p.setQuantity(0);p.setMinimumStock(0);return p;}@Test void acceptsValidProduct(){assertDoesNotThrow(()->ProductValidator.validate(valid()));}@Test void rejectsNegativeQuantity(){Product p=valid();p.setQuantity(-1);assertThrows(ValidationException.class,()->ProductValidator.validate(p));}@Test void rejectsNegativeMinimum(){Product p=valid();p.setMinimumStock(-1);assertThrows(ValidationException.class,()->ProductValidator.validate(p));}@Test void rejectsMissingName(){Product p=valid();p.setName(" ");assertThrows(ValidationException.class,()->ProductValidator.validate(p));}}
